 1	import * as React from 'react';
 2	import { EmptyState, EmptyStateBody, EmptyStateVariant, EmptyStateHeader } from '@patternfly/react-core';
 3	import { kialiStyle } from 'styles/StyleUtils';
 4	import { RefreshIntervalManual } from 'config/Config';
 5	import { IntervalInMilliseconds } from 'types/Common';
 6	import { NamespaceInfo } from 'types/NamespaceInfo';
 7	import { t } from 'utils/I18nUtils';
 8	
 9	type EmptyOverviewProps = {
10	  filteredNamespaces: NamespaceInfo[];
11	  loaded?: boolean;
12	  refreshInterval?: IntervalInMilliseconds;
13	};
14	
15	const emptyStateStyle = kialiStyle({
16	  height: '80%',
17	  marginRight: 'auto',
18	  marginLeft: 'auto',
19	  marginBottom: 10,
20	  marginTop: 10
21	});
22	
23	type EmptyOverviewState = {};
24	
25	export class EmptyOverview extends React.Component<EmptyOverviewProps, EmptyOverviewState> {
26	  render(): React.ReactNode {
27	    if (this.props.refreshInterval === RefreshIntervalManual && !this.props.loaded) {
28	      return (
29	        <EmptyState
30	          id="empty-vl-manual"
31	          data-test="manual-refresh"
32	          variant={EmptyStateVariant.lg}
33	          className={emptyStateStyle}
34	        >
35	          <EmptyStateHeader titleText={t('Manual refresh required')} headingLevel="h5" />
36	          <EmptyStateBody>
37	            {t(
38	              'The refresh interval is set to "Manual". To render the overview, select your desired filters and options and then click the Refresh button. Or, if preferred, change the setting to the desired interval.'
39	            )}
40	          </EmptyStateBody>
41	        </EmptyState>
42	      );
43	    }
44	
45	    if (this.props.filteredNamespaces.length === 0) {
46	      return (
47	        <EmptyState id="empty-vl-manual" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
48	          <EmptyStateHeader titleText={t('No unfiltered namespaces')} headingLevel="h5" />
49	          <EmptyStateBody>
50	            {t('Either all namespaces are being filtered or the user has no permission to access namespaces.')}
51	          </EmptyStateBody>
52	        </EmptyState>
53	      );
54	    }
55	
56	    return this.props.children;
57	  }
58	}

